# solution.py
"""Team Collaboration Manager.

A self-contained, thread-safe, in-memory back-end for a team collaboration
platform.  It provides:

* User registration and profile management.
* Project creation and lifecycle management.
* Task management with assignment, scheduling and status tracking.
* Threaded messaging with file attachments (project- or task-scoped).
* A performance dashboard (completion rates, completion times, peer ratings).
* Reporting (project progress, team performance, individual performance) with
  CSV and PDF export.

Design notes
------------
The manager is composed of six cooperating services -- ``users``,
``projects``, ``tasks``, ``messages``, ``performance`` and ``reports`` -- that
all share a single :class:`_Context`.  The context owns the data stores, the
global id generator and a single re-entrant lock, so every service serialises
through the *same* lock.  This keeps cross-entity invariants (cascading
deletes, secondary indexes, globally-unique ids) consistent under concurrent
access.

All accessor methods return deep copies of stored entities, so callers can
freely mutate the returned objects (or returned lists) without corrupting the
internal state.

Only the Python standard library is used.
"""

from __future__ import annotations

import copy
import csv
import io
import re
import threading
from dataclasses import dataclass, field
from datetime import datetime, timedelta
from enum import Enum
from typing import Callable, Dict, List, Optional, Set


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Role granted to a registered user."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    """Lifecycle status of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of report produced by the reporting service."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when supplied input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with the current state."""


# ---------------------------------------------------------------------------
# Entities
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""
    created_at: Optional[datetime] = None


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    created_at: datetime
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    created_at: datetime
    feedback: str = ""
    task_id: Optional[int] = None


# ---------------------------------------------------------------------------
# Validation helpers
# ---------------------------------------------------------------------------
_EMAIL_RE = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")


def _require_text(value: object, field_name: str) -> str:
    """Return a stripped non-empty string or raise :class:`ValidationError`."""

    if not isinstance(value, str) or not value.strip():
        raise ValidationError("{0} must be a non-empty string".format(field_name))
    return value.strip()


def _require_email(value: object) -> str:
    """Return a validated, stripped email address."""

    if not isinstance(value, str):
        raise ValidationError("email must be a string")
    candidate = value.strip()
    if not _EMAIL_RE.match(candidate):
        raise ValidationError("invalid email address: {0!r}".format(value))
    return candidate


def _clone(obj):
    """Return a deep copy so callers cannot mutate internal state."""

    return copy.deepcopy(obj)


# ---------------------------------------------------------------------------
# Shared context
# ---------------------------------------------------------------------------
class _Context:
    """Holds all shared state, indexes, the id generator and the lock."""

    def __init__(self, now: Callable[[], datetime]):
        self._lock = threading.RLock()
        self._now = now
        self._next_id = 1

        # Primary stores -------------------------------------------------
        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}

        # Secondary indexes ---------------------------------------------
        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}
        self.tasks_by_project: Dict[int, Set[int]] = {}
        self.tasks_by_assignee: Dict[int, Set[int]] = {}
        self.messages_by_project: Dict[int, Set[int]] = {}
        self.messages_by_task: Dict[int, Set[int]] = {}
        self.ratings_by_ratee: Dict[int, Set[int]] = {}

    # -- id generation --------------------------------------------------
    def next_id(self) -> int:
        """Return the next globally-unique id (caller must hold the lock)."""

        new_id = self._next_id
        self._next_id += 1
        return new_id

    def now(self) -> datetime:
        return self._now()

    # -- existence helpers ---------------------------------------------
    def require_user(self, user_id: int) -> User:
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def require_project(self, project_id: int) -> Project:
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def require_task(self, task_id: int) -> Task:
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def require_message(self, message_id: int) -> Message:
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    # -- index maintenance ---------------------------------------------
    def index_task_assignee(self, task: Task, assignee_id: Optional[int]) -> None:
        """Move ``task`` to ``assignee_id`` in the assignee index."""

        current = task.assignee_id
        if current is not None:
            bucket = self.tasks_by_assignee.get(current)
            if bucket is not None:
                bucket.discard(task.id)
                if not bucket:
                    del self.tasks_by_assignee[current]
        if assignee_id is not None:
            self.tasks_by_assignee.setdefault(assignee_id, set()).add(task.id)
        task.assignee_id = assignee_id

    def unindex_task(self, task: Task) -> None:
        project_bucket = self.tasks_by_project.get(task.project_id)
        if project_bucket is not None:
            project_bucket.discard(task.id)
            if not project_bucket:
                del self.tasks_by_project[task.project_id]
        if task.assignee_id is not None:
            assignee_bucket = self.tasks_by_assignee.get(task.assignee_id)
            if assignee_bucket is not None:
                assignee_bucket.discard(task.id)
                if not assignee_bucket:
                    del self.tasks_by_assignee[task.assignee_id]

    def unindex_message(self, message: Message) -> None:
        if message.project_id is not None:
            bucket = self.messages_by_project.get(message.project_id)
            if bucket is not None:
                bucket.discard(message.id)
                if not bucket:
                    del self.messages_by_project[message.project_id]
        if message.task_id is not None:
            bucket = self.messages_by_task.get(message.task_id)
            if bucket is not None:
                bucket.discard(message.id)
                if not bucket:
                    del self.messages_by_task[message.task_id]

    # -- aggregation helpers -------------------------------------------
    def tasks_for_assignee(self, user_id: int) -> List[Task]:
        ids = self.tasks_by_assignee.get(user_id, set())
        return [self.tasks[tid] for tid in sorted(ids)]

    def tasks_for_project(self, project_id: int) -> List[Task]:
        ids = self.tasks_by_project.get(project_id, set())
        return [self.tasks[tid] for tid in sorted(ids)]

    def ratings_for_ratee(self, user_id: int) -> List[Rating]:
        ids = self.ratings_by_ratee.get(user_id, set())
        return [self.ratings[rid] for rid in sorted(ids)]


def _completion_seconds(task: Task) -> Optional[float]:
    """Return the seconds a completed task took, or ``None``."""

    if task.status is not TaskStatus.COMPLETED:
        return None
    if task.started_at is None or task.completed_at is None:
        return None
    return (task.completed_at - task.started_at).total_seconds()


def _status_breakdown(tasks: List[Task]) -> Dict[str, object]:
    """Compute count / completion metrics for a collection of tasks."""

    total = len(tasks)
    completed = [t for t in tasks if t.status is TaskStatus.COMPLETED]
    in_progress = [t for t in tasks if t.status is TaskStatus.IN_PROGRESS]
    not_started = [t for t in tasks if t.status is TaskStatus.NOT_STARTED]

    durations = [
        _completion_seconds(t)
        for t in completed
        if _completion_seconds(t) is not None
    ]
    average_time = (sum(durations) / len(durations)) if durations else None
    completion_rate = (len(completed) / total) if total else 0.0

    return {
        "total_tasks": total,
        "completed_tasks": len(completed),
        "in_progress_tasks": len(in_progress),
        "not_started_tasks": len(not_started),
        "completion_rate": completion_rate,
        "average_completion_time": average_time,
    }


# ---------------------------------------------------------------------------
# Service base
# ---------------------------------------------------------------------------
class _Service:
    """Base class that exposes the shared lock and context to each service."""

    def __init__(self, ctx: _Context):
        self._ctx = ctx
        self._lock = ctx._lock


# ---------------------------------------------------------------------------
# User service
# ---------------------------------------------------------------------------
class UserService(_Service):
    def register_user(
        self,
        username: str,
        email: str,
        role: UserRole = UserRole.MEMBER,
    ) -> User:
        name = _require_text(username, "username")
        addr = _require_email(email)
        if not isinstance(role, UserRole):
            raise ValidationError("role must be a UserRole")

        with self._lock:
            if name in self._ctx.username_index:
                raise DuplicateError("username {0!r} already in use".format(name))
            if addr in self._ctx.email_index:
                raise DuplicateError("email {0!r} already in use".format(addr))

            user = User(
                id=self._ctx.next_id(),
                username=name,
                email=addr,
                role=role,
                created_at=self._ctx.now(),
            )
            self._ctx.users[user.id] = user
            self._ctx.username_index[name] = user.id
            self._ctx.email_index[addr] = user.id
            return _clone(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            return _clone(self._ctx.require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return [_clone(self._ctx.users[uid]) for uid in sorted(self._ctx.users)]

    def update_user(
        self,
        user_id: int,
        username: Optional[str] = None,
        email: Optional[str] = None,
        role: Optional[UserRole] = None,
    ) -> User:
        with self._lock:
            user = self._ctx.require_user(user_id)

            new_name = None
            if username is not None:
                new_name = _require_text(username, "username")
                owner = self._ctx.username_index.get(new_name)
                if owner is not None and owner != user_id:
                    raise DuplicateError(
                        "username {0!r} already in use".format(new_name)
                    )

            new_email = None
            if email is not None:
                new_email = _require_email(email)
                owner = self._ctx.email_index.get(new_email)
                if owner is not None and owner != user_id:
                    raise DuplicateError(
                        "email {0!r} already in use".format(new_email)
                    )

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if new_name is not None and new_name != user.username:
                del self._ctx.username_index[user.username]
                self._ctx.username_index[new_name] = user_id
                user.username = new_name
            if new_email is not None and new_email != user.email:
                del self._ctx.email_index[user.email]
                self._ctx.email_index[new_email] = user_id
                user.email = new_email
            if role is not None:
                user.role = role

            return _clone(user)

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            user = self._ctx.require_user(user_id)

            for project in self._ctx.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError(
                        "user {0} owns project {1}".format(user_id, project.id)
                    )

            for task in self._ctx.tasks_for_assignee(user_id):
                if task.status is not TaskStatus.COMPLETED:
                    raise ConflictError(
                        "user {0} has open task {1}".format(user_id, task.id)
                    )

            # Detach the user from any completed tasks they were assigned.
            for task in list(self._ctx.tasks_for_assignee(user_id)):
                self._ctx.index_task_assignee(task, None)

            self._ctx.ratings_by_ratee.pop(user_id, None)
            self._ctx.username_index.pop(user.username, None)
            self._ctx.email_index.pop(user.email, None)
            del self._ctx.users[user_id]


# ---------------------------------------------------------------------------
# Project service
# ---------------------------------------------------------------------------
class ProjectService(_Service):
    def create_project(
        self,
        name: str,
        start_date: datetime,
        end_date: datetime,
        owner_id: int,
        description: str = "",
    ) -> Project:
        clean_name = _require_text(name, "name")
        if not isinstance(start_date, datetime) or not isinstance(end_date, datetime):
            raise ValidationError("start_date and end_date must be datetimes")
        if end_date < start_date:
            raise ValidationError("end_date cannot be before start_date")

        with self._lock:
            self._ctx.require_user(owner_id)
            project = Project(
                id=self._ctx.next_id(),
                name=clean_name,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description or "",
                created_at=self._ctx.now(),
            )
            self._ctx.projects[project.id] = project
            self._ctx.tasks_by_project.setdefault(project.id, set())
            return _clone(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            return _clone(self._ctx.require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                _clone(self._ctx.projects[pid])
                for pid in sorted(self._ctx.projects)
            ]

    def update_project(
        self,
        project_id: int,
        name: Optional[str] = None,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
        description: Optional[str] = None,
    ) -> Project:
        with self._lock:
            project = self._ctx.require_project(project_id)

            new_name = None
            if name is not None:
                new_name = _require_text(name, "name")

            new_start = project.start_date
            if start_date is not None:
                if not isinstance(start_date, datetime):
                    raise ValidationError("start_date must be a datetime")
                new_start = start_date

            new_end = project.end_date
            if end_date is not None:
                if not isinstance(end_date, datetime):
                    raise ValidationError("end_date must be a datetime")
                new_end = end_date

            if new_end < new_start:
                raise ValidationError("end_date cannot be before start_date")

            if new_name is not None:
                project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not None:
                project.description = description

            return _clone(project)

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            self._ctx.require_project(project_id)

            # Cascade: remove tasks (and any messages attached to them).
            for task in self._ctx.tasks_for_project(project_id):
                for message in self._messages_for_task(task.id):
                    self._ctx.unindex_message(message)
                    self._ctx.messages.pop(message.id, None)
                self._ctx.unindex_task(task)
                self._ctx.tasks.pop(task.id, None)

            # Cascade: remove messages posted directly to the project.
            for message in self._messages_for_project(project_id):
                self._ctx.unindex_message(message)
                self._ctx.messages.pop(message.id, None)

            self._ctx.tasks_by_project.pop(project_id, None)
            del self._ctx.projects[project_id]

    def _messages_for_project(self, project_id: int) -> List[Message]:
        ids = self._ctx.messages_by_project.get(project_id, set())
        return [self._ctx.messages[mid] for mid in sorted(ids)]

    def _messages_for_task(self, task_id: int) -> List[Message]:
        ids = self._ctx.messages_by_task.get(task_id, set())
        return [self._ctx.messages[mid] for mid in sorted(ids)]


# ---------------------------------------------------------------------------
# Task service
# ---------------------------------------------------------------------------
class TaskService(_Service):
    def create_task(
        self,
        project_id: int,
        title: str,
        assignee_id: Optional[int] = None,
        deadline: Optional[datetime] = None,
    ) -> Task:
        with self._lock:
            project = self._ctx.require_project(project_id)
            clean_title = _require_text(title, "title")

            if deadline is not None:
                if not isinstance(deadline, datetime):
                    raise ValidationError("deadline must be a datetime")
                if deadline < project.start_date:
                    raise ValidationError(
                        "deadline cannot be before the project start date"
                    )

            if assignee_id is not None:
                self._ctx.require_user(assignee_id)

            task = Task(
                id=self._ctx.next_id(),
                project_id=project_id,
                title=clean_title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=None,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._ctx.now(),
            )
            self._ctx.tasks[task.id] = task
            self._ctx.tasks_by_project.setdefault(project_id, set()).add(task.id)
            if assignee_id is not None:
                self._ctx.index_task_assignee(task, assignee_id)
            return _clone(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            return _clone(self._ctx.require_task(task_id))

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._ctx.require_project(project_id)
            return [_clone(t) for t in self._ctx.tasks_for_project(project_id)]

    def list_tasks_by_assignee(self, user_id: int) -> List[Task]:
        with self._lock:
            self._ctx.require_user(user_id)
            return [_clone(t) for t in self._ctx.tasks_for_assignee(user_id)]

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            self._ctx.require_user(assignee_id)
            self._ctx.index_task_assignee(task, assignee_id)
            return _clone(task)

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        return self.assign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            self._ctx.index_task_assignee(task, None)
            return _clone(task)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            if deadline is not None:
                if not isinstance(deadline, datetime):
                    raise ValidationError("deadline must be a datetime")
                project = self._ctx.require_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError(
                        "deadline cannot be before the project start date"
                    )
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        if not isinstance(status, TaskStatus):
            raise ValidationError("status must be a TaskStatus")
        with self._lock:
            task = self._ctx.require_task(task_id)
            now = self._ctx.now()

            if status is TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status is TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status is TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now

            task.status = status
            return _clone(task)


# ---------------------------------------------------------------------------
# Message service
# ---------------------------------------------------------------------------
class MessageService(_Service):
    def post_message(
        self,
        author_id: int,
        body: str,
        project_id: Optional[int] = None,
        task_id: Optional[int] = None,
        parent_id: Optional[int] = None,
        attachments: Optional[List] = None,
    ) -> Message:
        with self._lock:
            self._ctx.require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id must be supplied"
                )
            if project_id is not None:
                self._ctx.require_project(project_id)
            if task_id is not None:
                self._ctx.require_task(task_id)

            text = body if isinstance(body, str) else ""
            attachment_specs = list(attachments or [])
            if not text.strip() and not attachment_specs:
                raise ValidationError(
                    "message must have a body or at least one attachment"
                )

            if parent_id is not None:
                self._ctx.require_message(parent_id)

            now = self._ctx.now()
            built = [
                self._build_attachment(spec, author_id, now)
                for spec in attachment_specs
            ]

            message = Message(
                id=self._ctx.next_id(),
                author_id=author_id,
                body=text,
                created_at=now,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
                edited_at=None,
            )
            self._ctx.messages[message.id] = message
            if project_id is not None:
                self._ctx.messages_by_project.setdefault(
                    project_id, set()
                ).add(message.id)
            if task_id is not None:
                self._ctx.messages_by_task.setdefault(task_id, set()).add(message.id)
            return _clone(message)

    @staticmethod
    def _build_attachment(spec, uploader_id: int, when: datetime) -> Attachment:
        try:
            filename, data = spec
        except (TypeError, ValueError):
            raise ValidationError(
                "attachment must be a (filename, data) pair"
            )
        clean_name = _require_text(filename, "filename")
        size = len(data) if data is not None else 0
        return Attachment(
            filename=clean_name,
            size=size,
            uploaded_by=uploader_id,
            uploaded_at=when,
        )

    def edit_message(self, message_id: int, editor_id: int, new_body: str) -> Message:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            text = new_body if isinstance(new_body, str) else ""
            if not text.strip() and not message.attachments:
                raise ValidationError("message body cannot be empty")
            message.body = text
            message.edited_at = self._ctx.now()
            return _clone(message)

    def add_attachment(
        self,
        message_id: int,
        uploader_id: int,
        filename: str,
        data: bytes,
    ) -> Message:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may attach to this message"
                )
            attachment = self._build_attachment(
                (filename, data), uploader_id, self._ctx.now()
            )
            message.attachments.append(attachment)
            return _clone(message)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._ctx.require_project(project_id)
            ids = self._ctx.messages_by_project.get(project_id, set())
            return [_clone(self._ctx.messages[mid]) for mid in sorted(ids)]

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._ctx.require_task(task_id)
            ids = self._ctx.messages_by_task.get(task_id, set())
            return [_clone(self._ctx.messages[mid]) for mid in sorted(ids)]

    def delete_message(self, message_id: int, requester_id: int) -> None:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError(
                    "only the author may delete this message"
                )
            self._ctx.unindex_message(message)
            del self._ctx.messages[message_id]


# ---------------------------------------------------------------------------
# Performance service
# ---------------------------------------------------------------------------
class PerformanceService(_Service):
    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._ctx.require_user(user_id)
            tasks = self._ctx.tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status is TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._ctx.require_user(user_id)
            durations = [
                _completion_seconds(t)
                for t in self._ctx.tasks_for_assignee(user_id)
                if _completion_seconds(t) is not None
            ]
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        with self._lock:
            self._ctx.require_user(rater_id)
            self._ctx.require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if isinstance(score, bool) or not isinstance(score, int):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._ctx.require_task(task_id)

            rating = Rating(
                id=self._ctx.next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                created_at=self._ctx.now(),
                feedback=feedback or "",
                task_id=task_id,
            )
            self._ctx.ratings[rating.id] = rating
            self._ctx.ratings_by_ratee.setdefault(ratee_id, set()).add(rating.id)
            return _clone(rating)

    def get_ratings_summary(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            self._ctx.require_user(user_id)
            ratings = self._ctx.ratings_for_ratee(user_id)
            count = len(ratings)
            average = (sum(r.score for r in ratings) / count) if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [_clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            self._ctx.require_user(user_id)
            tasks = self._ctx.tasks_for_assignee(user_id)
            breakdown = _status_breakdown(tasks)

            ratings = self._ctx.ratings_for_ratee(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": breakdown["total_tasks"],
                "completed_tasks": breakdown["completed_tasks"],
                "in_progress_tasks": breakdown["in_progress_tasks"],
                "not_started_tasks": breakdown["not_started_tasks"],
                "completion_rate": breakdown["completion_rate"],
                "average_completion_time": breakdown["average_completion_time"],
                "rating_count": rating_count,
                "rating_average": rating_average,
            }


# ---------------------------------------------------------------------------
# Report service
# ---------------------------------------------------------------------------
class ReportService(_Service):
    def project_progress_report(self, project_id: int) -> Dict[str, object]:
        with self._lock:
            self._ctx.require_project(project_id)
            tasks = self._ctx.tasks_for_project(project_id)
            now = self._ctx.now()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee: Dict[int, List[Task]] = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.status is not TaskStatus.COMPLETED
                    and task.deadline < now
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    per_assignee.setdefault(task.assignee_id, []).append(task)

            completed = status_counts[TaskStatus.COMPLETED.value]
            total = len(tasks)
            completion_rate = (completed / total) if total else 0.0

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": {
                    uid: _status_breakdown(subset)
                    for uid, subset in per_assignee.items()
                },
            }

    def team_performance_report(
        self, project_id: Optional[int] = None
    ) -> Dict[str, object]:
        with self._lock:
            if project_id is not None:
                self._ctx.require_project(project_id)
                tasks = self._ctx.tasks_for_project(project_id)
            else:
                tasks = list(self._ctx.tasks.values())

            grouped: Dict[int, List[Task]] = {}
            for task in tasks:
                if task.assignee_id is not None:
                    grouped.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(grouped):
                rows.append(self._performance_row(user_id, grouped[user_id]))

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "scope_project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            self._ctx.require_user(user_id)
            tasks = self._ctx.tasks_for_assignee(user_id)
            row = self._performance_row(user_id, tasks)
            now = self._ctx.now()
            overdue = sum(
                1
                for t in tasks
                if t.deadline is not None
                and t.status is not TaskStatus.COMPLETED
                and t.deadline < now
            )
            report = dict(row)
            report.update(
                {
                    "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                    "overdue_tasks": overdue,
                    "tasks": [_clone(t) for t in tasks],
                }
            )
            return report

    def _performance_row(self, user_id: int, tasks: List[Task]) -> Dict[str, object]:
        breakdown = _status_breakdown(tasks)
        ratings = self._ctx.ratings_for_ratee(user_id)
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count if rating_count else 0.0
        )
        row = {"user_id": user_id}
        row.update(breakdown)
        row["rating_count"] = rating_count
        row["rating_average"] = rating_average
        return row

    # -- export ---------------------------------------------------------
    def export_report(self, report: Dict[str, object], fmt: ReportFormat):
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dictionary")
        if fmt is ReportFormat.CSV:
            return _report_to_csv(report)
        return _report_to_pdf(report)


# ---------------------------------------------------------------------------
# Export helpers
# ---------------------------------------------------------------------------
def _csv_cell(value: object) -> str:
    if value is None:
        return ""
    if isinstance(value, float):
        # Keep integers tidy, otherwise full precision.
        return ("%g" % value) if value == int(value) else repr(value)
    return str(value)


def _report_to_csv(report: Dict[str, object]) -> str:
    buffer = io.StringIO()
    writer = csv.writer(buffer)
    rows = report.get("rows")
    if isinstance(rows, list):
        if rows:
            columns = list(rows[0].keys())
        else:
            columns = list(report.get("columns") or ["user_id"])
        writer.writerow(columns)
        for row in rows:
            writer.writerow([_csv_cell(row.get(col)) for col in columns])
    else:
        writer.writerow(["field", "value"])
        for key, value in report.items():
            if isinstance(value, dict):
                for sub_key, sub_value in value.items():
                    writer.writerow(
                        ["{0}.{1}".format(key, sub_key), _csv_cell(sub_value)]
                    )
            elif isinstance(value, list):
                writer.writerow([key, "{0} items".format(len(value))])
            else:
                writer.writerow([key, _csv_cell(value)])
    return buffer.getvalue()


def _pdf_escape(text: str) -> str:
    return (
        text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
    )


def _report_lines(report: Dict[str, object]) -> List[str]:
    lines = ["Report: {0}".format(report.get("report_type", "report"))]
    rows = report.get("rows")
    if isinstance(rows, list):
        for row in rows:
            lines.append(
                "; ".join("{0}={1}".format(k, row.get(k)) for k in row)
            )
    else:
        for key, value in report.items():
            if isinstance(value, dict):
                inner = ", ".join(
                    "{0}={1}".format(sk, sv) for sk, sv in value.items()
                )
                lines.append("{0}: {1}".format(key, inner))
            elif isinstance(value, list):
                lines.append("{0}: {1} items".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, value))
    return lines or ["Report"]


def _report_to_pdf(report: Dict[str, object]) -> bytes:
    lines = _report_lines(report)

    content_ops = ["BT", "/F1 12 Tf", "72 720 Td", "14 TL"]
    for index, line in enumerate(lines):
        if index:
            content_ops.append("T*")
        content_ops.append("({0}) Tj".format(_pdf_escape(line)))
    content_ops.append("ET")
    content = "\n".join(content_ops).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>",
        b"<< /Length "
        + str(len(content)).encode("ascii")
        + b" >>\nstream\n"
        + content
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    out = bytearray(b"%PDF-1.4\n")
    offsets = []
    for number, body in enumerate(objects, start=1):
        offsets.append(len(out))
        out += str(number).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

    xref_position = len(out)
    total = len(objects) + 1
    out += b"xref\n0 " + str(total).encode("ascii") + b"\n"
    out += b"0000000000 65535 f \n"
    for offset in offsets:
        out += ("%010d 00000 n \n" % offset).encode("ascii")
    out += (
        b"trailer\n<< /Size "
        + str(total).encode("ascii")
        + b" /Root 1 0 R >>\nstartxref\n"
        + str(xref_position).encode("ascii")
        + b"\n%%EOF\n"
    )
    return bytes(out)


