        self.add_attachment = self.messages.add_attachment
        self.list_messages_by_project = self.messages.list_messages_by_project
        self.list_messages_by_task = self.messages.list_messages_by_task
        self.delete_message = self.messages.delete_message

        # Performance operations
        self.get_completion_rate = self.performance.get_completion_rate
        self.get_average_completion_time = (
            self.performance.get_average_completion_time
        )
        self.submit_rating = self.performance.submit_rating
        self.get_ratings_summary = self.performance.get_ratings_summary
        self.get_user_dashboard = self.performance.get_user_dashboard

        # Reporting operations
        self.project_progress_report = self.reports.project_progress_report
        self.team_performance_report = self.reports.team_performance_report
